package runtime

import (
	"sync/atomic"

	"socialpredict/logger"
)

const (
	ReadinessEventOpen   = logger.EventReadinessOpen
	ReadinessEventClosed = logger.EventReadinessClosed

	readinessComponent   = "runtime"
	readinessOperation   = "ReadinessTransition"
	readinessStateOpen   = "open"
	readinessStateClosed = "closed"
)

// Readiness tracks whether the process should receive traffic.
type Readiness struct {
	ready  atomic.Bool
	logger *logger.RuntimeLogger
}

func NewReadiness() *Readiness {
	return NewReadinessWithLogger(logger.Standard())
}

// NewReadinessWithLogger creates a readiness gate with an explicit runtime logger.
func NewReadinessWithLogger(runtimeLogger *logger.RuntimeLogger) *Readiness {
	if runtimeLogger == nil {
		runtimeLogger = logger.Standard()
	}
	return &Readiness{logger: runtimeLogger}
}

func (r *Readiness) MarkReady() {
	if r == nil {
		return
	}
	if r.ready.Swap(true) {
		return
	}
	r.logTransition(ReadinessEventOpen, readinessStateOpen)
}

func (r *Readiness) MarkNotReady() {
	if r == nil {
		return
	}
	if !r.ready.Swap(false) {
		return
	}
	r.logTransition(ReadinessEventClosed, readinessStateClosed)
}

func (r *Readiness) Ready() bool {
	if r == nil {
		return false
	}
	return r.ready.Load()
}

func (r *Readiness) logTransition(event, state string) {
	runtimeLogger := r.logger
	if runtimeLogger == nil {
		runtimeLogger = logger.Standard()
	}
	runtimeLogger.Info(
		readinessComponent,
		"readiness state changed",
		logger.Event(event),
		logger.Operation(readinessOperation),
		logger.State(state),
	)
}

package runtime

import (
	"bytes"
	"strings"
	"testing"

	"socialpredict/logger"
)

func TestReadinessDefaultsNotReady(t *testing.T) {
	readiness := NewReadiness()

	if readiness.Ready() {
		t.Fatalf("expected new readiness gate to start not ready")
	}
}

func TestReadinessTransitions(t *testing.T) {
	readiness := NewReadiness()

	readiness.MarkReady()
	if !readiness.Ready() {
		t.Fatalf("expected readiness gate to report ready after MarkReady")
	}

	readiness.MarkNotReady()
	if readiness.Ready() {
		t.Fatalf("expected readiness gate to report not ready after MarkNotReady")
	}
}

func TestReadinessTransitionsEmitStableOperationalEvents(t *testing.T) {
	var buffer bytes.Buffer
	readiness := NewReadinessWithLogger(logger.New(&buffer))

	readiness.MarkReady()
	readiness.MarkReady()
	readiness.MarkNotReady()
	readiness.MarkNotReady()

	output := buffer.String()
	for _, want := range []string{
		`component="runtime"`,
		`operation="ReadinessTransition"`,
		`event="readiness.open"`,
		`state="open"`,
		`event="readiness.closed"`,
		`state="closed"`,
	} {
		if !strings.Contains(output, want) {
			t.Fatalf("expected %q in output, got %q", want, output)
		}
	}
	if strings.Count(output, `event="readiness.open"`) != 1 {
		t.Fatalf("expected one readiness-open event, got %q", output)
	}
	if strings.Count(output, `event="readiness.closed"`) != 1 {
		t.Fatalf("expected one readiness-closed event, got %q", output)
	}
}

package runtime

import (
	"context"
	"testing"
	"time"

	"socialpredict/models/modelstesting"

